# Error Handlers
@app.errorhandler(401)
def unauthorized(error):
    return jsonify({"error": "Unauthorized", "description": error.description}), 401

@app.errorhandler(403)
def forbidden(error):
    return jsonify({"error": "Forbidden", "description": error.description}), 403

@app.errorhandler(404)
def not_found(error):
    return jsonify({"error": "Not Found", "description": error.description}), 404

@app.errorhandler(500)
def internal_server_error(error):
    return jsonify({"error": "Internal Server Error", "description": str(error)}), 500

# Example Token Provisioning (for testing purposes, in a real scenario, this would be done by the Authorization Server)
@app.route('/_debug/issue_token', methods=['POST'])
def debug_issue_token():
    # This endpoint is purely for demonstrating token validation.
    # In a real setup, tokens are issued by an Authorization Server.
    data = request.get_json()
    if not data or not all(k in data for k in ['token', 'client_id', 'expires_in', 'scopes']):
        abort(400, description="Missing required fields: token, client_id, expires_in, scopes")

    token_str = data['token']
    client_id = data['client_id']
    user_id = data.get('user_id')
    expires_in_seconds = data['expires_in']
    scopes = " ".join(data['scopes']) if isinstance(data['scopes'], list) else data['scopes']

    import datetime
    expires_at = datetime.datetime.utcnow() + datetime.timedelta(seconds=expires_in_seconds)

    try:
        new_token = AccessToken(
            token=token_str,
            client_id=client_id,
            user_id=user_id,
            expires_at=expires_at,
            scopes=scopes
        )
        db.session.add(new_token)
        db.session.commit()
        return jsonify({"message": "Token issued successfully", "token": token_str}), 201
    except IntegrityError:
        db.session.rollback()
        return jsonify({"message": "Token already exists or other integrity error"}), 409
    except Exception as e:
        db.session.rollback()
        return jsonify({"message": f"Error issuing token: {str(e)}"}), 500

